namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string CourseCode { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "The abstract science of number, quantity, and space." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and linguistic analysis." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Examination of past events and their impact on the present." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD from MIT and has 15 years of experience teaching introductory computer science. Her research focuses on CS education and pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures & Algorithms", CourseCode = "CS 201", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Okafor", InstructorBio = "Dr. Okafor is an award-winning researcher in algorithm optimization. He previously worked at Google Research before joining academia.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Operating Systems", CourseCode = "CS 340", Description = "Principles of operating system design including process management, memory management, file systems, and concurrency.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Prof. Maria Gonzalez", InstructorBio = "Prof. Gonzalez contributed to the Linux kernel for a decade and brings deep systems expertise to the classroom.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH 151", Description = "Introduction to differential calculus covering limits, derivatives, and applications of differentiation.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a dedicated mathematics educator with research interests in real analysis and mathematical modeling.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Nakamura", InstructorBio = "Dr. Nakamura's research bridges pure mathematics and machine learning applications.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Differential Equations", CourseCode = "MATH 310", Description = "Ordinary differential equations, Laplace transforms, systems of equations, and numerical methods.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a dedicated mathematics educator with research interests in real analysis and mathematical modeling.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Title = "General Physics I", CourseCode = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM + Fri Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Patel", InstructorBio = "Dr. Patel is an experimental physicist whose work on superconductors has been published in Nature and Science.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Electromagnetism", CourseCode = "PHYS 230", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Lisa Fernandez", InstructorBio = "Dr. Fernandez specializes in photonics and has mentored over 40 graduate students during her career.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Title = "Creative Writing", CourseCode = "ENG 205", Description = "Workshop-based course exploring fiction, poetry, and creative nonfiction. Students develop a portfolio of original work.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Prof. David Achebe", InstructorBio = "Prof. Achebe is a published novelist and poet whose works have appeared in The New Yorker and Granta.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "American Literature", CourseCode = "ENG 310", Description = "Survey of American literary traditions from the colonial period through the 21st century.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Karen Whitfield", InstructorBio = "Dr. Whitfield is a scholar of African-American literature and has authored three books on the Harlem Renaissance.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Title = "World History: 1500–Present", CourseCode = "HIST 102", Description = "Global history from the Age of Exploration to the modern era, examining colonialism, revolutions, and globalization.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma is a historian of South Asian and global history with expertise in post-colonial studies.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
            new() { Id = 12, Title = "The Ancient World", CourseCode = "HIST 201", Description = "Civilizations of Mesopotamia, Egypt, Greece, and Rome. Explores politics, culture, and daily life in antiquity.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Dr. Marcus Webb", InstructorBio = "Dr. Webb has led archaeological expeditions in Greece and Turkey and is an expert in classical antiquity.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

