@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="hero">
        <h1>University Course Catalog</h1>
        <p class="lead">Explore our departments and courses. Find the right path for your academic journey.</p>
        <a href="/courses" class="btn btn-primary btn-lg">Browse All Courses</a>
    </div>

    <section class="mt-5">
        <h2>Featured Courses</h2>
        <div class="row mt-3">
            @foreach (var course in featuredCourses)
            {
                <div class="col-md-6 col-lg-4 mb-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.Title</h5>
                            <h6 class="card-subtitle mb-2 text-muted">@course.CourseCode &middot; @course.Credits credits</h6>
                            <p class="card-text">@course.Description[..Math.Min(course.Description.Length, 120)]&hellip;</p>
                        </div>
                        <div class="card-footer bg-transparent">
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mt-5">
        <h2>Departments</h2>
        <div class="row mt-3">
            @foreach (var dept in departments)
            {
                <div class="col-md-6 col-lg-4 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@dept.Name</h5>
                            <p class="card-text text-muted">@dept.Description</p>
                            <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Course Catalog</PageTitle>

<div class="container">
    <h1>Course Catalog</h1>

    <div class="row mb-4 mt-3">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search courses, instructors..."
                   @bind="searchTerm" @bind:event="oninput" @onkeyup="ApplyFilters" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId" @bind:after="ApplyFilters">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (filteredCourses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <p class="text-muted">Showing @filteredCourses.Count course(s)</p>
        <div class="row">
            @foreach (var course in filteredCourses)
            {
                <div class="col-md-6 col-lg-4 mb-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.Title</h5>
                            <h6 class="card-subtitle mb-2 text-muted">@course.CourseCode</h6>
                            <p class="card-text">
                                <span class="badge bg-secondary">@course.DepartmentName</span>
                                <span class="badge bg-info text-dark">@course.Credits credits</span>
                            </p>
                            <p class="card-text small">@course.Schedule</p>
                        </div>
                        <div class="card-footer bg-transparent">
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();
    private string searchTerm = "";
    private int selectedDepartmentId;

    [SupplyParameterFromQuery(Name = "departmentId")]
    public int? QueryDepartmentId { get; set; }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        if (QueryDepartmentId.HasValue)
        {
            selectedDepartmentId = QueryDepartmentId.Value;
        }
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(
            searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1 class="mt-3">Enrollment Request</h1>
    <p class="text-muted">Submit your enrollment request below. You will be contacted by the registrar's office.</p>

    @if (submitted)
    {
        <div class="alert alert-success mt-4">
            <h4>Request Submitted!</h4>
            <p>Thank you, <strong>@model.FullName</strong>. Your enrollment request for
                <strong>@courses.FirstOrDefault(c => c.Id == model.CourseId)?.Title</strong>
                has been received. The registrar's office will contact you at your university email.</p>
            <a href="/courses" class="btn btn-primary mt-2">Back to Catalog</a>
        </div>
    }
    else
    {
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="mt-4">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="fullName" class="form-label">Full Name</label>
                <InputText id="fullName" class="form-control" @bind-Value="model.FullName" />
                <ValidationMessage For="() => model.FullName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" placeholder="e.g., ABC12345" />
                <ValidationMessage For="() => model.StudentId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                    <option value="0">-- Select a course --</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.CourseCode — @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? QueryCourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (QueryCourseId.HasValue && model.CourseId == 0)
        {
            model.CourseId = QueryCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

